let result = $json.result || {};
if (typeof result === 'string') { try { result = JSON.parse(result); } catch { result = {}; } }
return [{ json: { ...result, chat_id: String($json.chat_id || '') } }];

if ($json.route !== 'direct') return [];
const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const status = String($json.status || 'help');
let reply = '';
if (status === 'recent') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Останні записи</b>

${items.map((item) => `${item.is_archived ? '📦' : '•'} <code>${e(item.short_id)}</code> — ${e(item.title)}
  ${e(item.content_type)} · ${e(item.status)}`).join('\n\n')}` : 'Пам’ять поки порожня.';
} else if (status === 'show') {
  const item = $json.item || {};
  const tags = Array.isArray(item.tags) ? item.tags : [];
  const files = Array.isArray(item.attachments) ? item.attachments : [];
  reply = `<b>${e(item.title)}</b>
<code>${e(item.short_id)}</code>${item.is_archived ? ' · 📦 архів' : ''}

${e(item.summary)}

<b>Проєкт:</b> ${e(item.project)}
<b>Категорія:</b> ${e(item.category)}
<b>Тип:</b> ${e(item.item_type)}
<b>Пріоритет:</b> ${e(item.priority)}
<b>Статус:</b> ${e(item.status)}${tags.length ? `
<b>Теги:</b> ${tags.map(e).join(', ')}` : ''}${files.length ? `
<b>Файли:</b> ${files.map(e).join(', ')}` : ''}${item.source_url ? `
<b>Джерело:</b> ${e(item.source_url)}` : ''}`;
} else if (status === 'archived') {
  reply = `📦 Запис <code>${e($json.short_id)}</code> переміщено в архів.
${e($json.title)}`;
} else if (status === 'delete_confirmation') {
  reply = `⚠️ <b>Підтвердження видалення</b>

<code>${e($json.short_id)}</code> — ${e($json.title)}

Це видалить запис із PostgreSQL, його вектори з Qdrant і окремий файл із B2, якщо на нього немає інших посилань.

Підтвердити протягом ${Number($json.expires_minutes || 10)} хвилин:
<code>/confirm ${e($json.token)}</code>

Скасувати:
<code>/cancel ${e($json.token)}</code>`;
} else if (status === 'cancelled') {
  reply = '✅ Видалення скасовано.';
} else if (status === 'unauthorized') {
  reply = '⛔ Цей Telegram-користувач не має доступу до пам’яті.';
} else if (status === 'token_required') {
  reply = 'Вкажіть код підтвердження: <code>/confirm КОД</code> або <code>/cancel КОД</code>.';
} else if (status === 'action_not_found') {
  reply = 'Код підтвердження не знайдено.';
} else if (status === 'action_not_pending') {
  reply = 'Ця дія вже виконана, скасована або її код прострочений.';
} else if (status === 'item_id_required') {
  reply = 'Вкажіть щонайменше 6 символів ID запису. Отримати ID: <code>/recent</code>.';
} else if (status === 'item_not_found') {
  reply = 'Запис із таким ID не знайдено.';
} else if (status === 'item_id_ambiguous') {
  reply = 'Цей фрагмент ID неоднозначний — вкажіть більше символів.';
} else {
  reply = `<b>Керування пам’яттю</b>

<code>/recent</code> — останні 10 записів
<code>/show ID</code> — деталі запису
<code>/archive ID</code> — перемістити в архів
<code>/reindex ID</code> — перебудувати RAG-індекс
<code>/delete ID</code> — підготувати безпечне видалення
<code>/confirm КОД</code> — підтвердити видалення
<code>/cancel КОД</code> — скасувати видалення`;
}
return [{ json: { chat_id: $json.chat_id, reply } }];

if ($json.route !== 'curation_direct') return [];
const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const status = String($json.status || 'help');
let reply = '';
if (status === 'review') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Черга перевірки</b>

${items.map((item) => `• <code>${e(item.short_id)}</code> — ${e(item.title)}
  ${e((Array.isArray(item.reasons) ? item.reasons : []).join(', '))}`).join('\n\n')}

Виправити: <code>/edit ID поле=значення</code>` : '✅ Записів, які потребують перевірки, немає.';
} else if (status === 'related') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Пов’язані з ${e($json.short_id)}</b>
${e($json.title)}

${items.map((item) => `• <code>${e(item.short_id)}</code> — ${e(item.title)}
  схожість ${Math.round(Number(item.score || 0) * 100)}% · ${e((Array.isArray(item.reasons) ? item.reasons : []).join(', '))}`).join('\n\n')}` : `Для <code>${e($json.short_id)}</code> пов’язаних записів поки не знайдено.`;
} else if (status === 'unarchived') {
  reply = `📤 Запис <code>${e($json.short_id)}</code> повернено з архіву.
${e($json.title)}`;
} else if (status === 'edit_spec_required') {
  reply = `Вкажіть зміни після ID. Приклад:
<code>/edit ID project=AI Studio; category=AI; priority=High; tags=n8n, Gemini</code>`;
} else if (status === 'edit_invalid_assignment') {
  reply = `Не розпізнано зміну <code>${e($json.value)}</code>. Використовуйте формат <code>поле=значення</code> і розділяйте поля крапкою з комою.`;
} else if (status === 'edit_unknown_value') {
  reply = `Невідоме значення <code>${e($json.value)}</code> для поля <code>${e($json.field)}</code>. Використайте назву з чинної таксономії.`;
} else if (status === 'edit_unknown_field') {
  reply = `Невідоме поле <code>${e($json.field)}</code>. Доступні: project, category, type, priority, tags, title, summary.`;
} else if (status === 'edit_empty_value') {
  reply = `Поле <code>${e($json.field)}</code> не може бути порожнім.`;
} else if (status === 'duplicates') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Знайдені дублікати</b>

${items.map((item) => `• Дубль <code>${e(item.duplicate_short_id)}</code> — ${e(item.duplicate_title)}
  Головний <code>${e(item.canonical_short_id)}</code> — ${e(item.canonical_title)}
  ${Math.round(Number(item.score || 0) * 100)}% · ${e(item.reason)}
  <code>/merge ${e(item.duplicate_short_id)} ${e(item.canonical_short_id)}</code>`).join('\n\n')}` : '✅ Неприбраних дублікатів не знайдено.';
} else if (status === 'graph') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Граф для ${e($json.short_id)}</b>
${e($json.title)}

${items.map((item) => `${item.direction === 'out' ? '→' : '←'} <b>${e(item.relation_type)}</b> ${Math.round(Number(item.score || 0) * 100)}%
  <code>${e(item.other_short_id)}</code> — ${e(item.other_title)}
  ${e(item.explanation || '')}`).join('\n\n')}` : `Для <code>${e($json.short_id)}</code> зв’язків поки немає.`;
} else if (status === 'file_not_available') {
  reply = `Для <code>${e($json.short_id)}</code> оригінальний файл у B2 відсутній. Текст і аналіз запису залишаються доступними через /show.`;
} else if (status === 'merge_confirmation') {
  reply = `⚠️ <b>Підтвердження злиття</b>

Дубль: <code>${e($json.source_short_id)}</code> — ${e($json.source_title)}
Головний: <code>${e($json.canonical_short_id)}</code> — ${e($json.canonical_title)}

Теги, вкладення, пам’ять і зв’язки перейдуть у головний запис. Дубль та його вектори буде видалено. B2-файли не видаляються.

Підтвердити протягом ${Number($json.expires_minutes || 10)} хвилин:
<code>/confirm ${e($json.token)}</code>

Скасувати:
<code>/cancel ${e($json.token)}</code>`;
} else if (status === 'merge_ids_required') {
  reply = 'Вкажіть ID дубля, потім ID головного запису: <code>/merge ДУБЛЬ ГОЛОВНИЙ</code>.';
} else if (status === 'merge_same_item') {
  reply = 'Не можна об’єднати запис із самим собою.';
} else if (status === 'action_not_pending') {
  reply = 'Ця дія вже виконана, скасована або прострочена.';
} else if (status === 'knowledge_not_ready') {
  reply = 'AI-аналіз цього запису ще не готовий. Спробуйте пізніше або перевірте його статус через /show.';
} else if (['item_id_required', 'item_not_found', 'item_id_ambiguous', 'unauthorized'].includes(status)) {
  const messages = { item_id_required: 'Вкажіть щонайменше 6 символів ID. Отримати ID: /recent.', item_not_found: 'Запис із таким ID не знайдено.', item_id_ambiguous: 'Фрагмент ID неоднозначний — вкажіть більше символів.', unauthorized: '⛔ Немає доступу до пам’яті.' };
  reply = e(messages[status]);
} else {
  reply = `<b>Керування пам’яттю</b>

<code>/recent</code> — останні записи
<code>/review</code> — черга перевірки
<code>/show ID</code> — деталі
<code>/edit ID поле=значення</code> — виправити аналіз
<code>/related ID</code> — пов’язані записи
<code>/graph ID</code> — граф зв’язків
<code>/duplicates</code> — черга дублікатів
<code>/file ID</code> — повернути оригінал
<code>/merge ДУБЛЬ ГОЛОВНИЙ</code> — об’єднати
<code>/archive ID</code> / <code>/unarchive ID</code>
<code>/reindex ID</code> — перебудувати RAG
<code>/delete ID</code> — безпечне видалення`;
}
return [{ json: { chat_id: $json.chat_id, reply } }];

const reply = String($json.reply || '');
const button = (text, data) => ({ text, additionalFields: { callback_data: data } });
const row = (...buttons) => ({ row: { buttons } });
const rows = [];
const uniqueIds = [...new Set([...reply.matchAll(/<code>([0-9a-f]{6,36})<\/code>/gi)].map((match) => match[1]))];
const addMenu = () => rows.push(row(button('☰ Команди', 'ia:memory')));

if (reply.includes('<b>Керування пам’яттю</b>')) {
  rows.push(row(button('🕘 Останні', 'ia:recent'), button('🔎 Перевірка', 'ia:review')));
  rows.push(row(button('🧩 Дублікати', 'ia:duplicates')));
} else if (reply.includes('<b>Останні записи</b>') || reply.includes('<b>Черга перевірки</b>') || reply.includes('<b>Пов’язані з ') || reply.includes('<b>Граф для ')) {
  for (const id of uniqueIds.slice(0, 10)) rows.push(row(button(`👁 ${id}`, `ia:show:${id}`)));
  addMenu();
} else if (reply.includes('<b>Знайдені дублікати</b>')) {
  const merges = [...reply.matchAll(/<code>\/merge\s+([0-9a-f]{6,36})\s+([0-9a-f]{6,36})<\/code>/gi)];
  for (const match of merges.slice(0, 8)) rows.push(row(button(`🔀 ${match[1]} → ${match[2]}`, `ia:merge:${match[1]}:${match[2]}`)));
  addMenu();
} else if (reply.includes('<b>Підтвердження видалення</b>') || reply.includes('<b>Підтвердження злиття</b>')) {
  const confirm = reply.match(/<code>\/confirm\s+([^<\s]+)<\/code>/i)?.[1];
  const cancel = reply.match(/<code>\/cancel\s+([^<\s]+)<\/code>/i)?.[1] || confirm;
  if (confirm) rows.push(row(button('✅ Підтвердити', `ia:confirm:${confirm}`), button('❌ Скасувати', `ia:cancel:${cancel}`)));
  else addMenu();
} else {
  const detail = reply.match(/^<b>[\s\S]*?<\/b>\n<code>([0-9a-f]{6,36})<\/code>/i);
  if (detail) {
    const id = detail[1];
    rows.push(row(button('🔗 Пов’язані', `ia:related:${id}`), button('🕸 Граф', `ia:graph:${id}`)));
    rows.push(row(button('📄 Файл', `ia:file:${id}`), button(reply.includes('📦 архів') ? '📤 Відновити' : '📦 Архів', `ia:${reply.includes('📦 архів') ? 'unarchive' : 'archive'}:${id}`)));
    rows.push(row(button('♻️ RAG', `ia:reindex:${id}`), button('🗑 Видалити', `ia:delete:${id}`)));
    addMenu();
  } else if (reply.includes('Вкажіть щонайменше 6 символів ID')) {
    rows.push(row(button('🕘 Обрати з останніх', 'ia:recent')));
    addMenu();
  } else {
    addMenu();
  }
}

return [{ json: { ...$json, inline_keyboard: { rows } } }];

const source = $('Prepare Safe Deletion').first().json;
let objects = source.objects_to_delete || [];
if (typeof objects === 'string') { try { objects = JSON.parse(objects); } catch { objects = []; } }
if (!Array.isArray(objects) || objects.length === 0) return [{ json: { ...source, skip_b2: true } }];
return objects.map((object) => ({ json: { ...source, skip_b2: false, storage_bucket: object.bucket, object_key: object.key } }));

const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const reply = $json.deleted ? `🗑 Запис <code>${e($json.short_id)}</code> видалено.
${e($json.title)}

PostgreSQL, Qdrant і незадубльований оригінал B2 очищено.` : 'Дію вже завершено або запис був видалений раніше.';
return [{ json: { chat_id: $json.chat_id, reply } }];

let attachments = $json.attachments || [];
if (typeof attachments === 'string') { try { attachments = JSON.parse(attachments); } catch { attachments = []; } }
return (Array.isArray(attachments) ? attachments : []).map((attachment) => ({ json: { ...attachment, chat_id: $json.chat_id, short_id: $json.short_id, title: $json.title } }));

let result = $json.result || {};
if (typeof result === 'string') { try { result = JSON.parse(result); } catch { result = {}; } }
return [{ json: { ...result, chat_id: String($json.chat_id || ''), inbox_item_id: result.canonical_item_id } }];

const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const reply = $json.merged ? `🔗 <b>Записи об’єднано</b>

Видалено дубль: <code>${e($json.source_short_id)}</code> — ${e($json.source_title)}
Головний запис: <code>${e($json.canonical_short_id)}</code> — ${e($json.canonical_title)}

Перенесено вкладень: ${Number($json.moved_attachments || 0)}
Додано тегів: ${Number($json.moved_tags || 0)}
RAG та зв’язки перебудовуються у фоні.` : 'Злиття не виконано: дія вже завершена або записи недоступні.';
return [{ json: { chat_id: $json.chat_id, reply } }];

const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const command = $('Normalize Command Result').first().json;
const changes = command.changes && typeof command.changes === 'object' ? Object.entries(command.changes).map(([key, value]) => `${key}=${value}`).join('; ') : '';
const heading = command.status === 'edited' ? '✏️ Аналіз виправлено' : '🔄 Переіндексацію запущено';
const detail = command.status === 'edited' ? `
<b>Зміни:</b> ${e(changes)}
RAG-індекс оновлюється у фоні.` : `
Старі фрагменти: ${Number($json.old_chunks_removed || 0)}. Новий RAG-індекс створюється у фоні.`;
return [{ json: { chat_id: $json.chat_id, reply: `${heading} для <code>${e($json.short_id)}</code>.
${e($json.title)}
${detail}` } }];
